record.field:
{
    "type": "object",
    "properties": {
        "partner_name": {"type": "string", "description": "Customer name"},
        "partner_id": {"type": "integer", "description": "Customer partner ID"},
        "product_name": {"type": "string", "description": "Product / service to invoice"},
        "amount": {"type": "number", "description": "Amount to invoice"},
        "description": {"type": "string", "description": "Invoice line description"},
        "due_date": {"type": "string", "format": "date", "description": "Payment due date"}
    },
    "required": ["partner_name"]
}

{
    "type": "object",
    "properties": {
        "partner_name": {"type": "string", "description": "Customer / vendor name"},
        "state": {"type": "string", "enum": ["draft", "posted", "cancelled"], "description": "Payment state filter"},
        "payment_type": {"type": "string", "enum": ["inbound", "outbound"], "description": "inbound=received, outbound=sent"},
        "date_from": {"type": "string", "format": "date", "description": "Payments from this date"},
        "date_to": {"type": "string", "format": "date", "description": "Payments until this date"},
        "limit": {"type": "integer", "description": "Max results (default 20)"}
    }
}

{
    "type": "object",
    "properties": {
        "invoice_ref": {"type": "string", "description": "Invoice reference to pay"},
        "invoice_id": {"type": "integer", "description": "Invoice ID"},
        "amount": {"type": "number", "description": "Payment amount (defaults to invoice balance)"},
        "journal_name": {"type": "string", "description": "Payment journal (e.g. Bank, Cash)"},
        "date": {"type": "string", "format": "date", "description": "Payment date (default today)"}
    },
    "required": ["invoice_ref"]
}

{
    "type": "object",
    "properties": {
        "account_type": {"type": "string", "description": "Account type: bank, cash, receivable, payable"},
        "journal_name": {"type": "string", "description": "Journal name to check"}
    }
}

{
    "type": "object",
    "properties": {
        "partner_name": {"type": "string", "description": "Vendor name"},
        "partner_id": {"type": "integer", "description": "Vendor partner ID"},
        "amount": {"type": "number", "description": "Bill amount"},
        "description": {"type": "string", "description": "Bill description / reference"},
        "due_date": {"type": "string", "format": "date", "description": "Payment due date"}
    },
    "required": ["partner_name"]
}
